import React from 'react';
import { Globe } from 'lucide-react';
import HeroBackground from './hero/HeroBackground';
import DeviceMockups from './hero/DeviceMockups';
import ServiceBar from './hero/ServiceBar';
import StatsBar from './hero/StatsBar';
import { ArrowRight } from 'lucide-react';

function HeroSection({ lang, setLang, t, scrollToSection }) {
  const screenshots = {
    laptop: '/images/dashboard-screenshot.png',
    phone: '/images/app-screenshot.png',
    tablet: '/images/tablet-screenshot.png'
  };

  return (
    <section className="relative min-h-screen overflow-hidden">
      {/* Background */}
      <HeroBackground />

      {/* Main content */}
      <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pt-32 pb-20">
        <div className="flex flex-col lg:flex-row items-center lg:items-start gap-12">

          {/* Left - Text content */}
          <div className="flex-1 text-center lg:text-left">
            {/* Line 1 */}
            <h1 className="text-4xl sm:text-5xl md:text-6xl font-black text-white leading-tight">
              Thiết Kế <span className="text-yellow-400">Web</span> &
            </h1>
            {/* Line 2 */}
            <h1 className="text-4xl sm:text-5xl md:text-6xl font-black text-yellow-400 leading-tight">
              Ứng Dụng
            </h1>
            {/* Line 3 */}
            <h1 className="text-4xl sm:text-5xl md:text-6xl font-black text-white leading-tight mb-6">
              Chuyên Nghiệp
            </h1>

            <p className="text-lg text-blue-100/90 mb-8 leading-relaxed italic">
              Giải pháp số tối ưu cho doanh nghiệp của bạn.
            </p>

            <div className="flex flex-col sm:flex-row gap-4 justify-center lg:justify-start">
              <button 
                onClick={() => window.location.href = '/contact'} 
                className="group bg-gradient-to-r from-red-500 to-red-600 text-white px-8 py-4 rounded-lg font-bold text-lg hover:from-red-600 hover:to-red-700 transition-all flex items-center justify-center space-x-2 hover:scale-105 shadow-xl border border-red-400"
              >
                <span>Nhận Tư Vấn</span>
                <ArrowRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
              </button>

              <button 
                onClick={() => scrollToSection('portfolio')} 
                className="bg-transparent border-2 border-white text-white px-8 py-4 rounded-lg font-bold text-lg hover:bg-white/10 transition-all hover:scale-105"
              >
                Xem Dự Án
              </button>
            </div>
          </div>

          {/* Right - Device mockups */}
          <div className="hidden lg:block relative h-[500px] flex-1">
            <DeviceMockups screenshots={screenshots} />
          </div>
        </div>

        {/* Language switcher */}
        <div className="absolute top-8 right-8">
          <button 
            onClick={() => setLang(lang === 'vi' ? 'en' : 'vi')} 
            className="flex items-center space-x-2 bg-white/10 backdrop-blur-sm text-white px-4 py-2 rounded-lg hover:bg-white/20 transition-all"
          >
            <Globe className="w-5 h-5" />
            <span className="font-medium">{lang === 'vi' ? 'EN' : 'VI'}</span>
          </button>
        </div>
      </div>

      {/* Service bar */}
      <div className="relative z-20 max-w-5xl mx-auto px-4 -mt-10">
        <ServiceBar lang={lang} />
      </div>

      {/* Stats */}
      <div className="relative z-10 max-w-4xl mx-auto px-4 mt-16">
        <StatsBar lang={lang} />
      </div>

      {/* CSS Animations */}
      <style>{`
        @keyframes float {
          0%, 100% { transform: translateY(0px); }
          50% { transform: translateY(-20px); }
        }
        @keyframes float-delay {
          0%, 100% { transform: translateY(0px); }
          50% { transform: translateY(-15px); }
        }
        @keyframes float-slow {
          0%, 100% { transform: translateY(0px); }
          50% { transform: translateY(-10px); }
        }
        .animate-float { animation: float 6s ease-in-out infinite; }
        .animate-float-delay { animation: float-delay 8s ease-in-out infinite; }
        .animate-float-slow { animation: float-slow 10s ease-in-out infinite; }
      `}</style>
    </section>
  );
}

export default HeroSection;
